GUICommonActivityRewardFloat = class("GUICommonActivityRewardFloat", IGUIWindow)

function GUICommonActivityRewardFloat:ctor(...)
    self.super.ctor(self, "CommonActivityRewardFloat.json", ...)
end

function GUICommonActivityRewardFloat:onLoad()
    self.llContent = self:getChildWindowByName("CommonActivityRewardFloat-Content", GUIType.Layout)
    self.llBackImage = self:getChildWindowByName("CommonActivityRewardFloat-BackImage", GUIType.Layout)
    self.llBackLine = self:getChildWindowByName("CommonActivityRewardFloat-Line", GUIType.Layout)
    self.ivImage = self:getChildWindowByName("CommonActivityRewardFloat-Image", GUIType.StaticImage)
    self.tvCount = self:getChildWindowByName("CommonActivityRewardFloat-Count", GUIType.StaticText)
    self.tvName = self:getChildWindowByName("CommonActivityRewardFloat-Name", GUIType.StaticText)
    self.tvDesc = self:getChildWindowByName("CommonActivityRewardFloat-Desc", GUIType.StaticText)
    self.btnClose = self:getChildWindowByName("CommonActivityRewardFloat-Close", GUIType.Button)
    self:hide()
    self.root:registerMouseEvent(GUIEvent.Click, function(events)
        self:hide()
        Game:handleTouchClick(events.position.x, events.position.y)
    end)
    self.btnClose:registerEvent(GUIEvent.ButtonClick, function(events)
        self:hide()
    end)
end

function GUICommonActivityRewardFloat:showReward(reward, window)
    self.root:SetVisible(true)
    self.llBackImage:SetVisible(true)
    self.llBackLine:SetVisible(true)
    self.tvDesc:SetArea({ 0, 0 }, { 0, -10 }, { 1, -24 }, { 1, -105 })

    UIHelper:setImageAdjustSize(self.ivImage, reward.image, 60, 60)
    self.tvName:SetText(Lang:getString(reward.name))
    self.tvDesc:SetText(Lang:getString(reward.desc))
    if not reward.numLang or reward.numLang == "#" then
        self.tvCount:SetText("x" .. reward.num)
    else
        self.tvCount:SetText(Lang:getString(reward.numLang))
    end
    self.llBackImage:SetBackImage("set:common_activity.json image:img_iconboard_" .. reward.quality)
    if window then
        local area1 = window:GetUnclippedOuterRect()
        local area2 = self.root:GetParent():GetUnclippedOuterRect()
        local centerX = area1[1] - area2[1] + (area1[3] - area1[1]) / 2
        local centerY = area1[2] - area2[2] + (area1[4] - area1[2]) / 2
        self.llContent:SetXPosition({ 0, centerX })
        self.llContent:SetYPosition({ 0, centerY - self.llContent:GetPixelSize().y })
    end
end

function GUICommonActivityRewardFloat:showDesc(desc, window)
    self.root:SetVisible(true)
    self.llBackImage:SetVisible(false)
    self.llBackLine:SetVisible(false)

    self.tvDesc:SetArea({ 0, 0 }, { 0, -10 }, { 1, -24 }, { 1, -20 })
    self.tvDesc:SetText(Lang:getString(desc))
    if window then
        local area1 = window:GetUnclippedOuterRect()
        local area2 = self.root:GetParent():GetUnclippedOuterRect()
        local centerX = area1[1] - area2[1] + (area1[3] - area1[1]) / 2
        local centerY = area1[2] - area2[2] + (area1[4] - area1[2]) / 2
        self.llContent:SetXPosition({ 0, centerX })
        self.llContent:SetYPosition({ 0, centerY - self.llContent:GetPixelSize().y })
    end
end

function GUICommonActivityRewardFloat:hide()
    self.root:SetVisible(false)
end

return GUICommonActivityRewardFloat